class WebViewScreen extends StatefulWidget {
  const WebViewScreen({Key? key}) : super(key: key);

  @override
  State<WebViewScreen> createState() => _WebViewScreenState();
}

class _WebViewScreenState extends State<WebViewScreen> {
  late final WebViewController _controller;
  bool _isLoading = true;
  String _errorMessage = '';
  final ImagePicker _imagePicker = ImagePicker();

  @override
  void initState() {
    super.initState();
    _initializeWebView();
  }

  void _initializeWebView() {
    _controller = WebViewController()
      ..setJavaScriptMode(JavaScriptMode.unrestricted)
      ..setBackgroundColor(Colors.white)
      ..setNavigationDelegate(
        NavigationDelegate(
          onProgress: (int progress) {
            if (progress == 100) {
              setState(() {
                _isLoading = false;
              });
            }
          },
          onPageStarted: (String url) {
            setState(() {
              _isLoading = true;
              _errorMessage = '';
            });
          },
          onPageFinished: (String url) {
            setState(() {
              _isLoading = false;
            });
          },
          onWebResourceError: (WebResourceError error) {
            setState(() {
              _isLoading = false;
              _errorMessage = 'Error loading page: ${error.description}';
            });
          },
          onNavigationRequest: (NavigationRequest request) {
            final uri = Uri.parse(request.url);
            if (!_isAllowedDomain(uri)) {
              _showSecurityAlert('Navigation to ${uri.host} is not allowed');
              return NavigationDecision.prevent;
            }
            return NavigationDecision.navigate;
          },
        ),
      )
      ..addJavaScriptChannel(
        'FlutterChannel',
        onMessageReceived: (JavaScriptMessage message) {
          _handleJavaScriptMessage(message.message);
        },
      )
      ..loadRequest(Uri.parse('https://your-mobile-website.com'));
  }

  bool _isAllowedDomain(Uri uri) {
    final allowedDomains = [
      'your-mobile-website.com',
      'www.your-mobile-website.com',
    ];
    return allowedDomains.contains(uri.host);
  }

  void _handleJavaScriptMessage(String message) {
    try {
      final data = jsonDecode(message);
      final action = data['action'] as String?;

      if (action == null) {
        _sendErrorToWeb('Invalid message format: missing action');
        return;
      }

      switch (action) {
        case 'openCamera':
          _openCamera();
          break;
        case 'openGallery':
          _openGallery();
          break;
        case 'requestNotificationPermission':
          _requestNotificationPermission();
          break;
        case 'showNotification':
          final title = data['title'] as String?;
          final body = data['body'] as String?;
          if (title != null && body != null) {
            _showNotification(title, body);
          } else {
            _sendErrorToWeb('Missing notification title or body');
          }
          break;
        case 'getDeviceInfo':
          _getDeviceInfo();
          break;
        default:
          _sendErrorToWeb('Unknown action: $action');
      }
    } catch (e) {
      _sendErrorToWeb('Error parsing message: $e');
    }
  }

  Future<void> _openCamera() async {
    try {
      final status = await Permission.camera.request();
      if (!status.isGranted) {
        _sendResultToWeb('camera', {'error': 'Camera permission denied'});
        return;
      }

      final XFile? photo = await _imagePicker.pickImage(
        source: ImageSource.camera,
        maxWidth: 1920,
        maxHeight: 1080,
        imageQuality: 85,
      );

      if (photo != null) {
        final bytes = await photo.readAsBytes();
        final base64Image = base64Encode(bytes);
        _sendResultToWeb('camera', {
          'success': true,
          'image': base64Image,
          'path': photo.path,
          'name': photo.name,
        });
      } else {
        _sendResultToWeb('camera', {'cancelled': true});
      }
    } catch (e) {
      _sendResultToWeb('camera', {'error': e.toString()});
    }
  }

  Future<void> _openGallery() async {
    try {
      final status = await Permission.photos.request();
      if (!status.isGranted) {
        _sendResultToWeb('gallery', {'error': 'Gallery permission denied'});
        return;
      }

      final XFile? image = await _imagePicker.pickImage(
        source: ImageSource.gallery,
        maxWidth: 1920,
        maxHeight: 1080,
        imageQuality: 85,
      );

      if (image != null) {
        final bytes = await image.readAsBytes();
        final base64Image = base64Encode(bytes);
        _sendResultToWeb('gallery', {
          'success': true,
          'image': base64Image,
          'path': image.path,
          'name': image.name,
        });
      } else {
        _sendResultToWeb('gallery', {'cancelled': true});
      }
    } catch (e) {
      _sendResultToWeb('gallery', {'error': e.toString()});
    }
  }

  Future<void> _requestNotificationPermission() async {
    try {
      final status = await Permission.notification.request();
      _sendResultToWeb('notificationPermission', {
        'granted': status.isGranted,
        'denied': status.isDenied,
        'permanentlyDenied': status.isPermanentlyDenied,
      });
    } catch (e) {
      _sendResultToWeb('notificationPermission', {'error': e.toString()});
    }
  }

  void _showNotification(String title, String body) {
    if (!mounted) return;
    
    ScaffoldMessenger.of(context).showSnackBar(
      SnackBar(
        content: Column(
          mainAxisSize: MainAxisSize.min,
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Text(
              title,
              style: const TextStyle(fontWeight: FontWeight.bold),
            ),
            const SizedBox(height: 4),
            Text(body),
          ],
        ),
        duration: const Duration(seconds: 4),
      ),
    );

    _sendResultToWeb('notification', {'success': true});
  }

  void _getDeviceInfo() {
    final info = {
      'platform': Platform.operatingSystem,
      'version': Platform.operatingSystemVersion,
      'isAndroid': Platform.isAndroid,
      'isIOS': Platform.isIOS,
    };
    _sendResultToWeb('deviceInfo', info);
  }

  void _sendResultToWeb(String action, Map<String, dynamic> data) {
    final message = jsonEncode({
      'action': action,
      'data': data,
    });
    final escapedMessage = message.replaceAll("'", "\\'");
    _controller.runJavaScript(
      "if (window.FlutterCallback) { window.FlutterCallback('$escapedMessage'); }",
    );
  }

  void _sendErrorToWeb(String error) {
    final message = jsonEncode({'error': error});
    final escapedMessage = message.replaceAll("'", "\\'");
    _controller.runJavaScript(
      "if (window.FlutterCallback) { window.FlutterCallback('$escapedMessage'); }",
    );
  }

  void _showSecurityAlert(String message) {
    if (!mounted) return;
    
    showDialog(
      context: context,
      builder: (context) => AlertDialog(
        title: const Text('Security Alert'),
        content: Text(message),
        actions: [
          TextButton(
            onPressed: () => Navigator.of(context).pop(),
            child: const Text('OK'),
          ),
        ],
      ),
    );
  }

  Future<void> _reloadPage() async {
    await _controller.reload();
  }

  Future<bool> _onWillPop() async {
    if (await _controller.canGoBack()) {
      await _controller.goBack();
      return false;
    }
    return true;
  }

